const REGION_CITIES = [
  {region:1, name:"Victoria",        lat:48.4284, lng:-123.3656},
  {region:2, name:"Vancouver",       lat:49.2827, lng:-123.1207},
  {region:3, name:"Kamloops",        lat:50.6745, lng:-120.3273},
  {region:4, name:"Cranbrook",       lat:49.5096, lng:-115.7688},
  {region:5, name:"Williams Lake",   lat:52.1418, lng:-122.1418},
  {region:6, name:"Smithers",        lat:54.7825, lng:-127.1669},
  {region:7, name:"Prince George",   lat:53.9171, lng:-122.7497},
  {region:7, name:"Fort St. John",   lat:56.2518, lng:-120.8487},
  {region:8, name:"Penticton",       lat:49.4991, lng:-119.5937},
  {region:6, name:"Atlin",           lat:59.5736, lng:-133.6942},
];

function addCityMarkers() {
  REGION_CITIES.forEach(city => {
    const icon = L.divIcon({
      className: 'city-label',
      html: '<div class="city-label-inner"><div class="city-dot"></div><span class="city-name">' + city.name + '</span></div>',
      iconAnchor: [4, 4],
    });
    L.marker([city.lat, city.lng], {icon: icon, interactive: false}).addTo(leafletMap);
  });
}

let leafletMap = null;
let mapInitialized = false;
let mapSelSpecies = new Set();
let mapCurrentMU = null;
let wmuLayer = null;

// Build lookup: MU number string -> array of draws
function buildMULookup() {
  const lookup = {};
  DATA.forEach(r => {
    const key = r.MU;
    if (!lookup[key]) lookup[key] = [];
    lookup[key].push(r);
  });
  return lookup;
}

// Best odds for a given MU (for coloring)
function bestOddsForMU(muDraws, species) {
  let draws = muDraws;
  if (species && species.size > 0) {
    draws = draws.filter(d => species.has(d.Species));
  }
  if (!draws.length) return null;
  return Math.max(...draws.map(d => d['%'] || 0));
}

function muFillColor(pct) {
  return '#5c1a1a';
}
function muBorderColor(pct) {
  return '#8b2020';
}

function initMap() {
  if (mapInitialized) { leafletMap && leafletMap.invalidateSize(); return; }
  mapInitialized = true;

  // Build species chips
  const allSpecies = [...new Set(DATA.map(r => r.Species))].sort();
  document.getElementById('mapSpeciesChips').innerHTML =
    ['All', ...allSpecies].map(s =>
      `<div class="map-chip${s==='All'?' active':''}" onclick="toggleMapSpecies('${s}')">${s}</div>`
    ).join('');

  leafletMap = L.map('leafletMap', {
    center: [54.5, -124.5],
    zoom: 5,
    minZoom: 4,
    maxZoom: 12,
    zoomControl: true,
  });

  // Base tile layer - dark style
  L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_matter_nolabels/{z}/{x}/{y}{r}.png', {
    attribution: '©OpenStreetMap ©CARTO',
    subdomains: 'abcd',
    maxZoom: 19
  }).addTo(leafletMap);

  loadWMULayer();
}

