function loadWMULayer() {
  const loading = document.getElementById('mapLoading');
  loading.style.display = 'none';
  renderWMULayer(WMU_GEOJSON);
  addCityMarkers();
}

function buildRegionLookup() {
  // Group draws by MU_General (region number)
  const lookup = {};
  DATA.forEach(r => {
    const key = r.MU_General;
    if (!lookup[key]) lookup[key] = [];
    lookup[key].push(r);
  });
  return lookup;
}

function renderWMULayer(geojson) {
  const regionLookup = buildRegionLookup();

  if (wmuLayer) { leafletMap.removeLayer(wmuLayer); }
  if (window._regionBorderLayer) { leafletMap.removeLayer(window._regionBorderLayer); }

  // Layer 1: filled polygons with NO visible border (border matches fill = invisible inner lines)
  wmuLayer = L.geoJSON(geojson, {
    style: feature => {
      const regionNum = parseInt(feature.properties.MU || '0');
      const draws = regionLookup[regionNum] || [];
      const filtered = mapSelSpecies.size > 0 ? draws.filter(d => mapSelSpecies.has(d.Species)) : draws;
      const pct = filtered.length ? Math.max(...filtered.map(d => d['%'] || 0)) : null;
      const fill = muFillColor(pct);
      return {
        fillColor: fill,
        fillOpacity: 0.85,
        color: '#2e2e2e',   // subtle dark grey for internal region boundaries
        weight: 1,
        opacity: 0.7,
      };
    },
    onEachFeature: (feature, layer) => {
      const regionNum = parseInt(feature.properties.MU || '0');
      const regionName = feature.properties.region_name || 'Region ' + regionNum;
      layer.on({
        mouseover: e => {
          // Highlight all polygons in same region
          wmuLayer.eachLayer(l => {
            if (parseInt(l.feature.properties.MU || '0') === regionNum) {
              const fill = '#7a2020';
              l.setStyle({ fillColor: fill, fillOpacity: 0.95, color: '#2e2e2e', weight: 1 });
            }
          });
          const draws = regionLookup[regionNum] || [];
          const filtered = mapSelSpecies.size > 0 ? draws.filter(d => mapSelSpecies.has(d.Species)) : draws;
          const best = filtered.length ? Math.max(...filtered.map(d => d['%'] || 0)) : null;
          const bestStr = best !== null ? fmt(best) + ' best odds' : 'No draws';
          layer.bindTooltip(
            '<strong style="font-size:13px">Region ' + regionNum + ' — ' + regionName + '</strong><br>' +
            filtered.length + ' draws · ' + bestStr,
            { sticky: true, className: 'mu-tooltip' }
          ).openTooltip();
        },
        mouseout: e => {
          wmuLayer.resetStyle(e.target);
          // Reset all polygons in this region
          wmuLayer.eachLayer(l => {
            const rn = parseInt(l.feature.properties.MU || '0');
            const draws = regionLookup[rn] || [];
            const filtered = mapSelSpecies.size > 0 ? draws.filter(d => mapSelSpecies.has(d.Species)) : draws;
            const pct = filtered.length ? Math.max(...filtered.map(d => d['%'] || 0)) : null;
            const fill = muFillColor(pct);
            l.setStyle({ fillColor: fill, fillOpacity: 0.85, color: '#2e2e2e', weight: 1, opacity: 0.7 });
          });
          layer.closeTooltip();
        },
        click: () => selectMUOnMap(regionNum, regionName)
      });
    }
  }).addTo(leafletMap);

  // Layer 2: outer BC boundary only in red — dissolve all regions into single shape using turf union
  // This ensures red lines appear ONLY on the outer province boundary, not between regions
  try {
    let dissolved = geojson.features[0];
    for (let i = 1; i < geojson.features.length; i++) {
      try {
        dissolved = turf.union(dissolved, geojson.features[i]);
      } catch(e) {
        // If union fails for a feature, skip it
      }
    }
    if (dissolved) {
      window._regionBorderLayer = L.geoJSON(dissolved, {
        style: () => ({
          fillColor: 'transparent',
          fillOpacity: 0,
          color: '#c43030',
          weight: 2.5,
          opacity: 0.95,
        }),
        interactive: false,
      }).addTo(leafletMap);
    }
  } catch(e) {
    console.warn('turf union failed, skipping outer border:', e);
  }
}

function selectMUOnMap(regionNum, regionName) {
  mapCurrentMU = regionNum;
  const regionLookup = buildRegionLookup();
  let draws = regionLookup[regionNum] || [];
  if (mapSelSpecies.size > 0) draws = draws.filter(d => mapSelSpecies.has(d.Species));

  const panel = document.getElementById('mapSelectedPanel');
  const viewBtn = document.getElementById('mapViewAllBtn');
  panel.style.display = 'flex';
  document.getElementById('mapSelMU').textContent = 'Region ' + regionNum + ' — ' + regionName;
  document.getElementById('mapSelArea').textContent = draws.length + ' draws available';

  if (draws.length === 0) {
    document.getElementById('mapSelDraws').innerHTML = '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No draws for this MU' + (mapSelSpecies.size>0?' with selected species':'') + '.</div>';
    viewBtn.style.display = 'none';
  } else {
    draws.sort((a,b) => (b['%']||0) - (a['%']||0));
    document.getElementById('mapSelDraws').innerHTML = draws.slice(0,8).map(r => {
      const cls = oddsClass(r['%']);
      const fr = computeHarvestAvg(r.yearly_fill_rates);
      const frStr = fr !== null ? `<span class="fill-badge ${fr>=50?'fill-high':fr>=25?'fill-mid':'fill-low'}" style="font-size:10px;padding:2px 6px">${fr}% success</span>` : '';
      const safeCode = (r.Code||'').replace(/'/g,"\\'");
      const safeMU = (r.MU||'').replace(/'/g,"\\'");
      return `<div class="map-draw-row">
        <div style="flex:1;min-width:0">
          <div class="map-draw-species">${r.Species} — ${r.Class}</div>
          <div class="map-draw-season">${r.Season}</div>
          ${frStr}
        </div>
        <div style="display:flex;flex-direction:column;align-items:flex-end;gap:3px;flex-shrink:0">
          <div class="map-draw-odds ${cls}">${fmt(r['%'])}</div>
          <button onclick="openDrawDetailByKey('${safeCode}','${safeMU}')" style="font-size:9px;padding:2px 6px;background:var(--bg-secondary);border:1px solid var(--border);border-radius:4px;color:var(--accent);cursor:pointer;white-space:nowrap">Details →</button>
        </div>
      </div>`;
    }).join('') + (draws.length > 8 ? `<div style="font-size:10px;color:var(--text-muted);text-align:center;padding:4px">+${draws.length-8} more</div>` : '');
    viewBtn.style.display = 'block';
    viewBtn.textContent = `View all ${draws.length} draw${draws.length!==1?'s':''} for MU ${muCode} →`;
  }
}

function viewMapMUDraws() {
  if (!mapCurrentMU) return;
  selMUs.clear();
  selMUs.add(parseInt(mapCurrentMU));
  if (mapSelSpecies.size > 0) { selSpecies = new Set(mapSelSpecies); }
  showPage('draws');
  buildSpeciesChips();
  buildMUList();
  applyFilters();
}

function toggleMapSpecies(s) {
  if (s === 'All') {
    mapSelSpecies.clear();
    document.querySelectorAll('.map-chip').forEach((c,i) => c.classList.toggle('active', i===0));
  } else {
    mapSelSpecies.has(s) ? mapSelSpecies.delete(s) : mapSelSpecies.add(s);
    document.querySelectorAll('.map-chip').forEach((c,i) => {
      if (i===0) c.classList.toggle('active', mapSelSpecies.size===0);
      else c.classList.toggle('active', mapSelSpecies.has(c.textContent));
    });
  }
  // Re-color the WMU layer
  if (wmuLayer) {
    const regionLookup = buildRegionLookup();
    wmuLayer.eachLayer(layer => {
      const regionNum = parseInt(layer.feature.properties.MU || '0');
      const draws = regionLookup[regionNum] || [];
      const filtered = mapSelSpecies.size > 0 ? draws.filter(d => mapSelSpecies.has(d.Species)) : draws;
      const pct = filtered.length ? Math.max(...filtered.map(d => d['%'] || 0)) : null;
      const fill = muFillColor(pct);
      layer.setStyle({ fillColor: fill, fillOpacity: 0.85, color: '#2e2e2e', weight: 1, opacity: 0.7 });
    });
  }
  // Update selected panel if open
  if (mapCurrentMU) selectMUOnMap(mapCurrentMU, '');
}




window.addEventListener('DOMContentLoaded', startApp);

// ── PHASE SLIDER ──
let _phaseIdx = 0;
function goToPhase(i) {
  _phaseIdx = i;
  const track = document.getElementById('phasesTrack');
  if (track) track.style.transform = `translateX(-${i * 100}%)`;
  for (let d = 0; d < 4; d++) {
    const dot = document.getElementById('phaseDot' + d);
    if (dot) dot.classList.toggle('active', d === i);
  }
  const counter = document.getElementById('phaseCounter');
  if (counter) counter.textContent = (i + 1) + ' / 4';
  const left = document.getElementById('phaseArrowLeft');
  const right = document.getElementById('phaseArrowRight');
  if (left) left.style.opacity = i === 0 ? '0.3' : '1';
  if (right) right.style.opacity = i === 3 ? '0.3' : '1';
}


