// ── PRIORITY CATEGORY DEFINITIONS ──
const AB_PRIORITY_CATS = [
  { key:'antlered_moose',            label:'Antlered Moose',            group:'Moose' },
  { key:'antlerless_moose',          label:'Antlerless Moose',          group:'Moose' },
  { key:'calf_moose',                label:'Calf Moose',                group:'Moose' },
  { key:'antlered_mule_deer',        label:'Antlered Mule Deer',        group:'Mule Deer' },
  { key:'antlerless_mule_deer',      label:'Antlerless Mule Deer',      group:'Mule Deer' },
  { key:'antlered_whitetail',        label:'Antlered White-tailed Deer',group:'White-tailed Deer' },
  { key:'antlerless_whitetail',      label:'Antlerless White-tailed Deer',group:'White-tailed Deer' },
  { key:'antlered_elk',              label:'Antlered Elk',              group:'Elk' },
  { key:'antlerless_elk',            label:'Antlerless Elk',            group:'Elk' },
  { key:'either_sex_elk',            label:'Either-Sex Elk',            group:'Elk' },
  { key:'antelope_archery',          label:'Antelope Archery',          group:'Antelope' },
  { key:'non_trophy_antelope',       label:'Non-trophy Antelope',       group:'Antelope' },
  { key:'trophy_antelope',           label:'Trophy Antelope',           group:'Antelope' },
  { key:'non_trophy_sheep',          label:'Non-trophy Sheep',          group:'Sheep' },
  { key:'trophy_sheep',              label:'Trophy Sheep',              group:'Sheep' },
  { key:'bison',                     label:'Bison',                     group:'Other' },
  { key:'cougar',                    label:'Cougar Special Licence',    group:'Other' },
];

const AB_PRIORITY_GROUPS = [...new Set(AB_PRIORITY_CATS.map(c => c.group))];

// ── HUNT ROW → PRIORITY KEY MAPPING ──
function getAbPriorityKey(draw, species) {
  const d = (draw||'').toLowerCase();
  const s = (species||'').toLowerCase();
  if (s.includes('moose')) {
    if (d.includes('calf')) return 'calf_moose';
    if (d.includes('antlerless')) return 'antlerless_moose';
    return 'antlered_moose';
  }
  if (s.includes('mule deer') || s.includes('mule_deer')) {
    if (d.includes('antlerless')) return 'antlerless_mule_deer';
    return 'antlered_mule_deer';
  }
  if (s.includes('white') || s.includes('whitetail') || s.includes('white-tailed')) {
    if (d.includes('antlerless')) return 'antlerless_whitetail';
    return 'antlered_whitetail';
  }
  if (s.includes('elk')) {
    if (d.includes('antlerless')) return 'antlerless_elk';
    if (d.includes('either') || d.includes('either-sex') || d.includes('either sex')) return 'either_sex_elk';
    return 'antlered_elk';
  }
  if (s.includes('antelope') || s.includes('pronghorn')) {
    if (d.includes('archery')) return 'antelope_archery';
    if (d.includes('trophy')) return 'trophy_antelope';
    return 'non_trophy_antelope';
  }
  if (s.includes('sheep')) {
    if (d.includes('trophy')) return 'trophy_sheep';
    return 'non_trophy_sheep';
  }
  if (s.includes('bison')) return 'bison';
  if (s.includes('cougar')) return 'cougar';
  return null;
}

// ── DEFAULT PROFILE ──
function defaultAbProfile() {
  const priorities = {};
  AB_PRIORITY_CATS.forEach(c => priorities[c.key] = '');
  return {
    residencyStatus: 'ab_resident',
    hasHost: false,
    hasWIN: true,
    hunterEdCompleted: true,
    isYouth: false,
    isSenior: false,
    priorities
  };
}

